/**
 * n8n Code Node
 * Parser Telegram input untuk payload JSON dari message.text atau file .json.
 */

function fail(message, details = {}) {
  throw new Error(
    `${message}${Object.keys(details).length ? ` | ${JSON.stringify(details)}` : ''}`
  );
}

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function isNonEmptyString(value) {
  return typeof value === 'string' && value.trim().length > 0;
}

function isValidNumber(value) {
  return typeof value === 'number' && Number.isFinite(value);
}

function extractYoutubeVideoId(sourceOrVideoId) {
  if (!isNonEmptyString(sourceOrVideoId)) return null;

  const value = sourceOrVideoId.trim();

  const patterns = [
    /youtube\.com\/watch\?v=([a-zA-Z0-9_-]{11})/,
    /youtu\.be\/([a-zA-Z0-9_-]{11})/,
    /youtube\.com\/shorts\/([a-zA-Z0-9_-]{11})/,
    /^([a-zA-Z0-9_-]{11})$/
  ];

  for (const pattern of patterns) {
    const match = value.match(pattern);
    if (match) return match[1];
  }

  return null;
}

function safeJsonParse(value) {
  try {
    return JSON.parse(value);
  } catch (error) {
    return null;
  }
}

async function getRawPayloadText(item, itemIndex, helpers) {
  const binaryKeys = Object.keys(item.binary || {});

  if (binaryKeys.length > 0) {
    const binaryPropertyName = binaryKeys.includes('data') ? 'data' : binaryKeys[0];
    const binaryMeta = item.binary[binaryPropertyName] || {};
    const fileName =
      binaryMeta.fileName ||
      item.json?.message?.document?.file_name ||
      item.json?.message?.document?.fileName ||
      null;

    const buffer = await helpers.getBinaryDataBuffer(itemIndex, binaryPropertyName);
    const raw = buffer.toString('utf8').trim();

    if (!isNonEmptyString(raw)) {
      fail('File JSON Telegram kosong atau tidak bisa dibaca sebagai UTF-8.', {
        binary_property: binaryPropertyName,
        file_name: fileName
      });
    }

    return {
      raw,
      input_type: 'telegram_json_file',
      binary_property: binaryPropertyName,
      file_name: fileName
    };
  }

  const text = item.json?.message?.text;

  if (isNonEmptyString(text)) {
    return {
      raw: text.trim(),
      input_type: 'telegram_text',
      binary_property: null,
      file_name: null
    };
  }

  fail('Payload Telegram tidak ditemukan. Kirim JSON sebagai message.text atau upload file .json, dan pastikan Telegram Trigger1 Additional Fields > Download aktif.', {
    available_json_keys: Object.keys(item.json || {}),
    has_binary: Boolean(item.binary),
    document: item.json?.message?.document || null
  });
}

function parsePayload(rawInput) {
  let parsed = safeJsonParse(rawInput.raw);

  if (parsed === null) {
    fail('Payload Telegram bukan JSON valid pada parse pertama.', {
      input_type: rawInput.input_type,
      file_name: rawInput.file_name,
      text_preview: rawInput.raw.slice(0, 500)
    });
  }

  if (typeof parsed === 'string') {
    const secondParsed = safeJsonParse(parsed.trim());

    if (secondParsed === null) {
      fail('Payload Telegram berhasil parse pertama, tapi gagal parse kedua.', {
        input_type: rawInput.input_type,
        file_name: rawInput.file_name,
        first_parse_type: typeof parsed,
        first_parse_preview: parsed.slice(0, 500)
      });
    }

    parsed = secondParsed;
  }

  if (!isObject(parsed)) {
    fail('Payload hasil parse harus berupa object JSON.', {
      input_type: rawInput.input_type,
      file_name: rawInput.file_name,
      parsed_type: typeof parsed
    });
  }

  return parsed;
}

function validatePayload(payload) {
  const errors = [];

  const videoId = extractYoutubeVideoId(
    payload.source ||
    payload.video_id ||
    payload.source_video?.video_id ||
    payload.render_payload?.source_video?.video_id
  );

  if (!videoId) {
    errors.push({
      field: 'video_id/source/source_video.video_id/render_payload.source_video.video_id',
      message: 'Wajib berisi YouTube URL valid atau video_id 11 karakter.'
    });
  }

  if (!Number.isInteger(payload.num_clips) || payload.num_clips < 1) {
    errors.push({
      field: 'num_clips',
      message: 'num_clips wajib integer minimal 1.'
    });
  }

  const allowedQuality = ['720', '1080', '1440', '2160'];

  if (!allowedQuality.includes(String(payload.quality))) {
    errors.push({
      field: 'quality',
      message: `quality harus salah satu dari: ${allowedQuality.join(', ')}.`
    });
  }

  if (!isNonEmptyString(payload.languages)) {
    errors.push({
      field: 'languages',
      message: 'languages wajib string, contoh: id,en.'
    });
  }

  if (!isObject(payload.render_payload)) {
    errors.push({
      field: 'render_payload',
      message: 'render_payload wajib object.'
    });
  }

  if (errors.length > 0) {
    fail('Payload utama tidak valid.', { errors });
  }

  const rp = payload.render_payload;

  if (!Number.isInteger(rp.clip_index) || rp.clip_index < 1) {
    fail('render_payload.clip_index wajib integer minimal 1.');
  }

  if (!isValidNumber(rp.viral_score) || rp.viral_score < 0 || rp.viral_score > 10) {
    fail('render_payload.viral_score wajib number antara 0 sampai 10.');
  }

  if (!isNonEmptyString(rp.clip_type)) {
    fail('render_payload.clip_type wajib string.');
  }

  if (!isValidNumber(rp.start)) {
    fail('render_payload.start wajib number.');
  }

  if (!isValidNumber(rp.end)) {
    fail('render_payload.end wajib number.');
  }

  if (rp.end <= rp.start) {
    fail('render_payload.end harus lebih besar dari start.', {
      start: rp.start,
      end: rp.end
    });
  }

  if (!isValidNumber(rp.duration) || rp.duration <= 0) {
    fail('render_payload.duration wajib number lebih dari 0.');
  }

  const calculatedDuration = Number((rp.end - rp.start).toFixed(2));

  if (Math.abs(calculatedDuration - rp.duration) > 0.3) {
    fail('render_payload.duration tidak sesuai dengan end - start.', {
      provided_duration: rp.duration,
      calculated_duration: calculatedDuration
    });
  }

  if (!isObject(rp.hook_3_5_seconds)) {
    fail('render_payload.hook_3_5_seconds wajib object.');
  }

  const hook = rp.hook_3_5_seconds;

  if (!isValidNumber(hook.start) || !isValidNumber(hook.end)) {
    fail('hook_3_5_seconds.start dan end wajib number.');
  }

  if (hook.end <= hook.start) {
    fail('hook_3_5_seconds.end harus lebih besar dari start.');
  }

  if (hook.start < rp.start || hook.end > rp.end) {
    fail('hook_3_5_seconds harus berada di dalam range clip.', {
      clip_start: rp.start,
      clip_end: rp.end,
      hook_start: hook.start,
      hook_end: hook.end
    });
  }

  if (!isNonEmptyString(hook.text)) {
    fail('hook_3_5_seconds.text wajib string.');
  }

  if (!Array.isArray(rp.selected_transcript) || rp.selected_transcript.length === 0) {
    fail('render_payload.selected_transcript wajib array dan tidak boleh kosong.');
  }

  rp.selected_transcript.forEach((segment, index) => {
    if (!isObject(segment)) {
      fail(`selected_transcript[${index}] wajib object.`);
    }

    if (!isValidNumber(segment.start)) {
      fail(`selected_transcript[${index}].start wajib number.`);
    }

    if (!isValidNumber(segment.end)) {
      fail(`selected_transcript[${index}].end wajib number.`);
    }

    if (segment.end <= segment.start) {
      fail(`selected_transcript[${index}].end harus lebih besar dari start.`);
    }

    if (!isNonEmptyString(segment.text)) {
      fail(`selected_transcript[${index}].text wajib string.`);
    }
  });

  if (!isObject(rp.youtube_metadata)) {
    fail('render_payload.youtube_metadata wajib object.');
  }

  if (!isNonEmptyString(rp.youtube_metadata.title)) {
    fail('youtube_metadata.title wajib string.');
  }

  if (!isNonEmptyString(rp.youtube_metadata.description)) {
    fail('youtube_metadata.description wajib string.');
  }

  if (!Array.isArray(rp.youtube_metadata.hashtags) || rp.youtube_metadata.hashtags.length === 0) {
    fail('youtube_metadata.hashtags wajib array dan tidak boleh kosong.');
  }

  rp.youtube_metadata.hashtags.forEach((tag, index) => {
    if (!isNonEmptyString(tag)) {
      fail(`youtube_metadata.hashtags[${index}] wajib string.`);
    }

    if (!tag.startsWith('#')) {
      fail(`youtube_metadata.hashtags[${index}] harus diawali #.`);
    }
  });

  if (!isObject(rp.subtitle_recommendation)) {
    fail('render_payload.subtitle_recommendation wajib object.');
  }

  if (!isNonEmptyString(rp.subtitle_recommendation.style)) {
    fail('subtitle_recommendation.style wajib string.');
  }

  if (
    !Number.isInteger(rp.subtitle_recommendation.max_words_per_line) ||
    rp.subtitle_recommendation.max_words_per_line < 1 ||
    rp.subtitle_recommendation.max_words_per_line > 8
  ) {
    fail('subtitle_recommendation.max_words_per_line wajib integer antara 1 sampai 8.');
  }

  if (!isObject(rp.editing_recommendation)) {
    fail('render_payload.editing_recommendation wajib object.');
  }

  if (
    !Array.isArray(rp.editing_recommendation.recommended_cut_style) ||
    rp.editing_recommendation.recommended_cut_style.length === 0
  ) {
    fail('editing_recommendation.recommended_cut_style wajib array dan tidak boleh kosong.');
  }

  return {
    video_id: videoId,
    calculated_duration: calculatedDuration
  };
}

const output = [];
const items = $input.all();

for (let index = 0; index < items.length; index++) {
  const item = items[index];
  const rawInput = await getRawPayloadText(item, index, this.helpers);
  const payload = parsePayload(rawInput);
  const validationResult = validatePayload(payload);
  const message = item.json?.message || {};

  output.push({
    json: {
      source: `https://youtu.be/${validationResult.video_id}`,
      video_id: validationResult.video_id,
      num_clips: payload.num_clips,
      quality: String(payload.quality),
      languages: payload.languages.trim(),

      render_payload: {
        ...payload.render_payload,
        calculated_duration: validationResult.calculated_duration
      },

      source_video: payload.source_video || payload.render_payload.source_video || {
        video_id: validationResult.video_id,
        job_id: null,
        status: null
      },

      telegram: {
        update_id: item.json?.update_id ?? null,
        message_id: message.message_id ?? null,
        chat_id: message.chat?.id ?? null,
        username: message.from?.username ?? null,
        first_name: message.from?.first_name ?? null,
        last_name: message.from?.last_name ?? null,
        input_type: rawInput.input_type,
        file_name: rawInput.file_name,
        binary_property: rawInput.binary_property
      },

      validation: {
        valid: true,
        message: 'Payload Telegram JSON berhasil diparse dan siap diproses.'
      }
    }
  });
}

return output;

