const original = $('Code in JavaScript2').first().json;
const result = $input.first().json;

const API_BASE_URL = 'http://localhost:8088';

const renderPayload = original.render_payload || {};
const yt = renderPayload.youtube_metadata;

if (!yt) {
  throw new Error('youtube_metadata tidak ditemukan dari render_payload');
}

const video_id = original.video_id || original.source_video?.video_id || renderPayload.source_video?.video_id;

if (!video_id) {
  throw new Error('video_id tidak ditemukan dari original payload');
}

let files = Array.isArray(result.files) ? result.files : [];

// Fallback: jika files kosong, gunakan path local storage langsung
let watermarkedVideo = null;

if (files.length === 0) {
  const relativePath = `free-viral-shorts/${video_id}/watermarked/${video_id}_wm.mp4`;

  watermarkedVideo = {
    filename: `${video_id}_wm.mp4`,
    path: relativePath,
    absolute_path: `/Users/agusrachman/Documents/Codex/content-short/storage/${relativePath}`,
    download_url: `${API_BASE_URL}/storage/${relativePath}`
  };

  console.log('[FALLBACK] Using local storage path:', relativePath);
} else {
  watermarkedVideo =
    files.find(file =>
      file.filename?.endsWith('.mp4') &&
      (
        file.filename.includes('_wm') ||
        file.path?.includes('/watermarked/') ||
        file.absolute_path?.includes('/watermarked/')
      )
    ) ||
    files.find(file => file.filename?.endsWith('.mp4'));
}

if (!watermarkedVideo) {
  throw new Error(`File video watermark tidak ditemukan. files=${JSON.stringify(files)}`);
}

const rawVideoPath =
  watermarkedVideo.absolute_path ||
  watermarkedVideo.file_path ||
  watermarkedVideo.path ||
  null;

const video_path = rawVideoPath?.startsWith('/')
  ? rawVideoPath
  : rawVideoPath
    ? `/Users/agusrachman/Documents/Codex/content-short/storage/${rawVideoPath}`
    : null;

const video_download_url =
  watermarkedVideo.download_url ||
  (
    watermarkedVideo.url
      ? `${API_BASE_URL}${watermarkedVideo.url.startsWith('/') ? '' : '/'}${watermarkedVideo.url}`
      : null
  );

if (!video_download_url) {
  throw new Error(`Download URL video tidak ditemukan: ${JSON.stringify(watermarkedVideo)}`);
}

const hashtags = Array.isArray(yt.hashtags)
  ? yt.hashtags.join(' ')
  : typeof yt.hashtags === 'string'
    ? yt.hashtags
    : '';

const hookText = renderPayload.hook_3_5_seconds?.text || '-';
const thumbnailText = yt.thumbnail_text || '-';
const viralScore = renderPayload.viral_score ?? '-';
const clipType = renderPayload.clip_type || '-';
const duration = renderPayload.duration || renderPayload.calculated_duration || '-';

const caption = [
  yt.title || 'Video pendek',
  hashtags
]
  .filter(Boolean)
  .join('\n\n')
  .slice(0, 1024);

// Object ini yang akan ditampilkan sebagai JSON rapi di Telegram
const metadataObject = {
  status: 'success',
  message: 'Render Watermark Selesai',
  video_id,
  video_path,
  video_download_url,
  caption,
  metadata: {
    title: yt.title || '-',
    description: yt.description || '-',
    hashtags: hashtags || '-',
    thumbnail_text: thumbnailText,
    hook: hookText,
    viral_score: viralScore,
    clip_type: clipType,
    duration_seconds: duration,
    source_video_id: video_id
  },
  file: {
    filename: watermarkedVideo.filename || '-',
    path: video_path,
    download_url: video_download_url
  }
};

// Pretty JSON untuk chat Telegram
const metadata_text = JSON.stringify(metadataObject, null, 2);

// Versi markdown code block agar tampil seperti JSON formatter di Telegram
const telegram_text = [
  '✅ Render Watermark Selesai',
  '',
  '```json',
  metadata_text,
  '```'
].join('\n');

return [
  {
    json: {
      video_id,
      video_path,
      video_download_url,
      caption,
      metadata_text,
      telegram_text,
      filename: watermarkedVideo.filename || video_path || video_download_url
    }
  }
];

